BlobRegistryAsyncWaiter::BlobRegistryAsyncWaiter(BlobRegistry* proxy)
    : proxy_(proxy)
{
}

BlobRegistryAsyncWaiter::~BlobRegistryAsyncWaiter() = default;

void BlobRegistryAsyncWaiter::Register(::mojo::PendingReceiver<::blink::mojom::Blob> blob, const std::string& uuid, const std::string& content_type,
    const std::string& content_disposition, std::vector<::blink::mojom::DataElementPtr> elements)
{
    base::RunLoop loop;
    proxy_->Register(std::move(blob), std::move(uuid), std::move(content_type), std::move(content_disposition), std::move(elements),
        base::BindOnce([](base::RunLoop* loop) { loop->Quit(); }, &loop));
    loop.Run();
}

void BlobRegistryAsyncWaiter::RegisterFromStream(const std::string& content_type, const std::string& content_disposition, uint64_t length_hint,
    ::mojo::ScopedDataPipeConsumerHandle data, ::mojo::PendingAssociatedRemote<ProgressClient> progress_client, ::blink::mojom::SerializedBlobPtr* out_blob)
{
    base::RunLoop loop;
    proxy_->RegisterFromStream(std::move(content_type), std::move(content_disposition), std::move(length_hint), std::move(data), std::move(progress_client),
        base::BindOnce(
            [](base::RunLoop* loop, ::blink::mojom::SerializedBlobPtr* out_blob, ::blink::mojom::SerializedBlobPtr blob) {
                *out_blob = std::move(blob);
                loop->Quit();
            },
            &loop, out_blob));
    loop.Run();
}

::blink::mojom::SerializedBlobPtr BlobRegistryAsyncWaiter::RegisterFromStream(const std::string& content_type, const std::string& content_disposition, uint64_t length_hint,
    ::mojo::ScopedDataPipeConsumerHandle data, ::mojo::PendingAssociatedRemote<ProgressClient> progress_client)
{
    ::blink::mojom::SerializedBlobPtr async_wait_result = mojo::DefaultConstructTraits::CreateInstance<::blink::mojom::SerializedBlobPtr>();
    RegisterFromStream(std::move(content_type), std::move(content_disposition), std::move(length_hint), std::move(data), std::move(progress_client), &async_wait_result);
    return async_wait_result;
}

void BlobRegistryAsyncWaiter::GetBlobFromUUID(::mojo::PendingReceiver<::blink::mojom::Blob> blob, const std::string& uuid)
{
    base::RunLoop loop;
    proxy_->GetBlobFromUUID(std::move(blob), std::move(uuid), base::BindOnce([](base::RunLoop* loop) { loop->Quit(); }, &loop));
    loop.Run();
}
